// Use MSBuild APIs to read binlog
#r "nuget: MSBuild.StructuredLogger, 2.2.449"

using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;
using System.Collections.Generic;

var build = BinaryLog.ReadBuild("build.binlog");

Console.WriteLine("=== BUILD SUCCEEDED: " + build.Succeeded + " ===\n");

// Collect all errors
var errors = new List<(string project, string code, string message, string file, int line)>();
build.VisitAllChildren<Error>(error =>
{
    var project = "";
    var parent = error.Parent;
    while (parent != null)
    {
        if (parent is Project p)
        {
            project = p.Name;
            break;
        }
        parent = (parent as TreeNode)?.Parent as BaseNode;
    }
    errors.Add((project, error.Code, error.Text, error.File, error.LineNumber));
});

Console.WriteLine($"Total errors: {errors.Count}\n");

foreach (var g in errors.GroupBy(e => e.project))
{
    Console.WriteLine($"--- Project: {g.Key} ---");
    foreach (var e in g)
    {
        Console.WriteLine($"  [{e.code}] {e.file}({e.line}): {e.message}");
    }
    Console.WriteLine();
}

// Also get warnings
var warnings = new List<(string project, string code, string message)>();
build.VisitAllChildren<Warning>(warning =>
{
    var project = "";
    var parent = warning.Parent;
    while (parent != null)
    {
        if (parent is Project p)
        {
            project = p.Name;
            break;
        }
        parent = (parent as TreeNode)?.Parent as BaseNode;
    }
    warnings.Add((project, warning.Code, warning.Text));
});

Console.WriteLine($"\nTotal warnings: {warnings.Count}");
foreach (var g in warnings.GroupBy(w => w.project))
{
    Console.WriteLine($"--- Project: {g.Key} ---");
    foreach (var w in g)
    {
        Console.WriteLine($"  [{w.code}] {w.message}");
    }
    Console.WriteLine();
}
