using Microsoft.Build.Logging.StructuredLogger;
using System;
using System.Linq;
using System.Collections.Generic;

var build = BinaryLog.ReadBuild("/tmp/sv-095bdac6c9b248a2911164c76451ffe9/build.binlog");

// Show all source files embedded in binlog
Console.WriteLine("=== EMBEDDED SOURCE FILES ===");
build.VisitAllChildren<SourceFile>(sf =>
{
    Console.WriteLine($"  {sf.Name}: {sf.SourceFilePath}");
});

// Show project references / items
Console.WriteLine("\n=== PROJECT DETAILS ===");
var seen = new HashSet<string>();
build.VisitAllChildren<Project>(p =>
{
    if (!seen.Add(p.Name + "|" + p.ProjectFile)) return;
    Console.WriteLine($"\nProject: {p.Name} -> {p.ProjectFile}");

    // Look for item groups, package references, project references
    p.VisitAllChildren<AddItem>(item =>
    {
        if (item.Name == "PackageReference" || item.Name == "ProjectReference")
        {
            Console.WriteLine($"  {item.Name}:");
            foreach (var child in item.Children.OfType<Item>())
            {
                Console.WriteLine($"    {child.Name} = {child.Text}");
            }
        }
    });
});

// Show the actual compiler invocations and what failed
Console.WriteLine("\n=== TASK FAILURES ===");
build.VisitAllChildren<Microsoft.Build.Logging.StructuredLogger.Task>(t =>
{
    bool hasError = false;
    t.VisitAllChildren<Error>(e => { hasError = true; });
    if (hasError)
    {
        var project = "";
        BaseNode parent = t.Parent;
        while (parent != null)
        {
            if (parent is Project p2) { project = p2.Name; break; }
            parent = (parent as TreeNode)?.Parent;
        }
        Console.WriteLine($"  Task '{t.Name}' in project '{project}' failed");
        t.VisitAllChildren<Error>(e =>
        {
            Console.WriteLine($"    [{e.Code}] {e.File}({e.LineNumber},{e.ColumnNumber}): {e.Text}");
        });
    }
});

// Check which projects reference which
Console.WriteLine("\n=== PROJECT DEPENDENCY GRAPH ===");
var projSeen2 = new HashSet<string>();
build.VisitAllChildren<Project>(p =>
{
    if (!projSeen2.Add(p.Name)) return;
    Console.WriteLine($"Project: {p.Name}");
    p.VisitAllChildren<AddItem>(item =>
    {
        if (item.Name == "ProjectReference")
        {
            foreach (var child in item.Children.OfType<Item>())
            {
                Console.WriteLine($"  -> depends on: {child.Text}");
            }
        }
    });
});

// Get the Api project build result
Console.WriteLine("\n=== PER-PROJECT BUILD RESULT ===");
var projResults = new HashSet<string>();
build.VisitAllChildren<Project>(p =>
{
    var key = p.Name;
    if (!projResults.Add(key)) return;
    bool hasErrors = false;
    p.VisitAllChildren<Error>(e => { hasErrors = true; });
    Console.WriteLine($"  {p.Name}: {(hasErrors ? "FAILED" : "OK")}");
});
